unsigned int nScreenBuffer[1024];
unsigned char ledbuf[8],ledx[8];
#define LEDS *(int *)0x280000
#define CTRGR *(int *)0x208000
#define CTRLCDCMDR *(int *)0x208001
#define CTRKEY *(int *)0x208001
#define CTRLCDCR *(int *)0x208002
#define CTRCLKEY *(int *)0x208002
#define CTRLCDLCR *(int *)0x208003
#define CTRLCDRCR *(int *)0x208004
#define CTRLA *(int *)0x208005
#define CTRLR *(int *)0x208007
unsigned int uPort8000;
unsigned int uWork,nCount=0,uN,uN1,nCount1,nDir;
void main(void)
{
 int nCount,nCursorCount;
 unsigned int nScanCode,nKeyCode;
 unsigned char cKey,cOldKey;
 unsigned int nSpeed;
 InitSysCtrl();
 InitXintf16Gpio();
 CTRGR=0x80;
 CTRGR=0x0;
 CTRGR=0x80;
 CTRLR=0;
 CTRLR=0x40;
 CTRLR=0xc1;
 uPort8000=CTRLCDCR;
 for ( nCount=0; nCount<8; nCount++ )
 {
   ledbuf[nCount]=0x0ff;
   ledx[nCount]=(nCount<<4);
 }
 RefreshLEDArray();
 nCount=nCursorCount=0;
 for (;;)
 {
   nScanCode=CTRLCDCMDR;
   nScanCode&=0x0ff;
   uPort8000=CTRLCDCR;
   if ( nScanCode!=0 )
   {
     if ( nScanCode==9 ) *(int *)0x208007=0x20;
     else
     {
       cKey=nScanCode;
       if ( cKey!=0 && cOldKey!=cKey )
       {
         *(int *)0x208007=0x0;
         Delay(100);
         *(int *)0x208007=0x40;
         Delay(100);
         cOldKey=cKey;
         switch ( cKey )
         {
           case 1: *(int *)0x208007=0x01; break;
           case 2: *(int *)0x208007=0x02; break;
           case 3: *(int *)0x208007=0x04; break;
           case 4: *(int *)0x208007=0x48; break;
           case 5: *(int *)0x208007=0x50; break;
           case 6: *(int *)0x208007=0x60; break;
           case 7: *(int *)0x208007=0x08; break;
           case 8: *(int *)0x208007=0x10; break;
         }
       }
     }
   }
   Delay(25);
   nCursorCount++; nCursorCount%=4;
   if ( nCursorCount==0 ) ledbuf[7]^=0x80;
 }
}
void RefreshLEDArray()
{
 int i;
 for ( i=0;i<8;i++ )
 {
   CTRGR=ledx[i];
   CTRLA=ledbuf[i];
 }
}
char ConvertScanToChar(unsigned char cScanCode)
{
 char cReturn;
 cReturn=0;
 switch ( cScanCode )
 {
 case SCANCODE_0: cReturn='0'; break;
 case SCANCODE_1: cReturn='1'; break;
 case SCANCODE_2: cReturn='2'; break;
 case SCANCODE_3: cReturn='3'; break;
 case SCANCODE_4: cReturn='4'; break;
 case SCANCODE_5: cReturn='5'; break;
 case SCANCODE_6: cReturn='6'; break;
 case SCANCODE_7: cReturn='7'; break;
 case SCANCODE_8: cReturn='8'; break;
 case SCANCODE_9: cReturn='9'; break;
 }
 return cReturn;
}

